// Service health check
app.get('/health/services', authenticateApiKey, async (req, res) => {
  const healthChecks = {};

  for (const [prefix, config] of Object.entries(BACKEND_SERVICES)) {
    try {
      const response = await axios.get(`${config.target}/health`, { timeout: 5000 });
      healthChecks[config.name] = {
        status: 'healthy',
        statusCode: response.status,
        prefix
      };
    } catch (error) {
      healthChecks[config.name] = {
        status: 'unhealthy',
        error: error.message,
        prefix
      };
    }
  }

  res.json({
    gateway: 'healthy',
    services: healthChecks,
    timestamp: new Date().toISOString()
  });
});

// List available routes
app.get('/routes', (req, res) => {
  res.json({
    available_routes: Object.entries(BACKEND_SERVICES).map(([prefix, config]) => ({
      prefix,
      name: config.name,
      target: config.target
    })),
    authentication: 'API key required via ?api_key=xxx or X-API-Key header'
  });
});

// Main proxy middleware - apply authentication and rate limiting
app.use('/api/*', authenticateApiKey, rateLimiter, async (req, res) => {
  const service = resolveService(req.path);

  if (!service) {
    debugLog('Service Not Found', {
      path: req.path,
      api_key: req.authenticatedApiKey
    });

    return res.status(404).json({
      error: 'Not Found',
      message: `No backend service configured for path: ${req.path}`,
      available_routes: Object.keys(BACKEND_SERVICES)
    });
  }

  // Build the target URL
  const targetPath = req.path;
  const targetUrl = `${service.target}${targetPath}`;

  // Build query string without api_key
  const forwardQuery = { ...req.query };
  delete forwardQuery.api_key;

  // Build forwarding headers
  const forwardHeaders = {
    ...req.headers,
    'x-api-key': req.authenticatedApiKey,
    'x-forwarded-for': req.ip,
    'x-forwarded-host': req.hostname,
    'x-forwarded-proto': req.protocol,
    'x-gateway-request-id': generateRequestId(),
    'x-original-url': req.originalUrl,
    host: new URL(service.target).host
  };

  // Remove hop-by-hop headers
  delete forwardHeaders['connection'];
  delete forwardHeaders['transfer-encoding'];

  debugLog('Forwarding Request', {
    service: service.name,
    target_url: targetUrl,
    method: req.method,
    api_key: req.authenticatedApiKey,
    forwarded_headers: {
      'x-api-key': forwardHeaders['x-api-key'],
      'x-forwarded-for': forwardHeaders['x-forwarded-for'],
      'x-gateway-request-id': forwardHeaders['x-gateway-request-id']
    },
    query: forwardQuery
  });

  try {
    const startTime = Date.now();

    const axiosConfig = {
      method: req.method.toLowerCase(),
      url: targetUrl,
      headers: forwardHeaders,
      params: forwardQuery,
      timeout: 30000, // 30 second timeout
      validateStatus: () => true, // Don't throw on any status code
      maxRedirects: 5
    };

    // Forward request body for methods that support it
    if (['POST', 'PUT', 'PATCH'].includes(req.method)) {
      axiosConfig.data = req.body;
    }

    const response = await axios(axiosConfig);
    const duration = Date.now() - startTime;

    debugLog('Backend Response Received', {
      service: service.name,
      target_url: targetUrl,
      method: req.method,
      api_key: req.authenticatedApiKey,
      status_code: response.status,
      duration_ms: duration,
      response_headers: {
        'content-type': response.headers['content-type'],
        'content-length': response.headers['content-length']
      }
    });

    // Forward response headers (filter out hop-by-hop headers)
    const excludeHeaders = ['transfer-encoding', 'connection', 'keep-alive'];
    Object.entries(response.headers).forEach(([key, value]) => {
      if (!excludeHeaders.includes(key.toLowerCase())) {
        res.set(key, value);
      }
    });

    // Add gateway headers
    res.set('X-Gateway-Service', service.name);
    res.set('X-Gateway-Duration', `${duration}ms`);

    res.status(response.status).send(response.data);

  } catch (error) {
    const duration = Date.now() - Date.now();

    debugLog('Proxy Error', {
      service: service.name,
      target_url: targetUrl,
      method: req.method,
      api_key: req.authenticatedApiKey,
      error: error.message,
      error_code: error.code,
      stack: error.stack
    });

    if (error.code === 'ECONNREFUSED') {
      return res.status(503).json({
        error: 'Service Unavailable',
        message: `Backend service "${service.name}" is not available.`,
        service: service.name
      });
    }

    if (error.code === 'ETIMEDOUT' || error.code === 'ECONNABORTED') {
      return res.status(504).json({
        error: 'Gateway Timeout',
        message: `Request to "${service.name}" timed out.`,
        service: service.name
      });
    }

    res.status(502).json({
      error: 'Bad Gateway',
      message: `Error communicating with backend service "${service.name}".`,
      details: error.message,
      service: service.name
    });
  }
});

// Generate a unique request ID
function generateRequestId() {
  return `gw-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
}

// 404 handler for non-API routes
